// MARK: - Password Hashing Service

class PasswordHashingService {
    
    static let shared = PasswordHashingService()
    
    private let saltLength = 32
    private let hashIterations: UInt32 = 10000
    private let derivedKeyLength = 64
    
    private init() {}
    
    // Generate a random salt
    func generateSalt() -> Data {
        var salt = Data(count: saltLength)
        salt.withUnsafeMutableBytes { bufferPointer in
            guard let baseAddress = bufferPointer.baseAddress else { return }
            _ = SecRandomCopyBytes(kSecRandomDefault, saltLength, baseAddress)
        }
        return salt
    }
    
    // Hash password using PBKDF2 with HMAC-SHA512 (available on all iOS versions)
    func hashPassword(_ password: String, salt: Data) -> Data? {
        guard let passwordData = password.data(using: .utf8) else { return nil }
        
        var derivedKey = Data(count: derivedKeyLength)
        
        let result = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            salt.withUnsafeBytes { saltBytes in
                passwordData.withUnsafeBytes { passwordBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                        passwordData.count,
                        saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        salt.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA512),
                        hashIterations,
                        derivedKeyBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        derivedKeyLength
                    )
                }
            }
        }
        
        guard result == kCCSuccess else { return nil }
        return derivedKey
    }
    
    // Create a storable hash string: iterations$salt$hash (all base64)
    func createHashString(password: String) -> String? {
        let salt = generateSalt()
        guard let hash = hashPassword(password, salt: salt) else { return nil }
        
        let saltBase64 = salt.base64EncodedString()
        let hashBase64 = hash.base64EncodedString()
        
        return "\(hashIterations)$\(saltBase64)$\(hashBase64)"
    }
    
    // Verify password against stored hash string
    func verifyPassword(_ password: String, againstHashString hashString: String) -> Bool {
        let components = hashString.components(separatedBy: "$")
        guard components.count == 3,
              let _ = UInt32(components[0]),
              let salt = Data(base64Encoded: components[1]),
              let storedHash = Data(base64Encoded: components[2]) else {
            return false
        }
        
        guard let computedHash = hashPassword(password, salt: salt) else { return false }
        
        // Constant-time comparison to prevent timing attacks
        return constantTimeCompare(computedHash, storedHash)
    }
    
    // Constant-time comparison to prevent timing attacks
    private func constantTimeCompare(_ a: Data, _ b: Data) -> Bool {
        guard a.count == b.count else { return false }
        var result: UInt8 = 0
        for i in 0..<a.count {
            result |= a[i] ^ b[i]
        }
        return result == 0
    }
}

// MARK: - Secure Local Storage

class SecurePasswordStore {
    
    static let shared = SecurePasswordStore()
    
    private let keychainService = "com.passwordstore.credentials"
    private let userDefaultsSuite = "com.passwordstore.metadata"
    
    private init() {}
    
    // MARK: - Keychain Operations
    
    // Save hash string to Keychain
    func savePasswordHash(forUsername username: String, hashString: String) -> Bool {
        // First delete any existing entry
        deletePasswordHash(forUsername: username)
        
        guard let data = hashString.data(using: .utf8) else { return false }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: username,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    // Retrieve hash string from Keychain
    func getPasswordHash(forUsername username: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: username,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        
        guard status == errSecSuccess,
              let data = item as? Data,
              let hashString = String(data: data, encoding: .utf8) else {
            return nil
        }
        
        return hashString
    }
    
    // Delete hash from Keychain
    @discardableResult
    func deletePasswordHash(forUsername username: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: username
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess || status == errSecItemNotFound
    }
    
    // Get all stored usernames
    func getAllUsernames() -> [String] {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecReturnAttributes as String: true,
            kSecMatchLimit as String: kSecMatchLimitAll
        ]
        
        var items: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &items)
        
        guard status == errSecSuccess,
              let results = items as? [[String: Any]] else {
            return []
        }
        
        return results.compactMap { $0[kSecAttrAccount as String] as? String }
    }
    
    // Check if username exists
    func usernameExists(_ username: String) -> Bool {
        return getPasswordHash(forUsername: username) != nil
    }
}

// MARK: - Authentication Manager

class AuthenticationManager {
    
    static let shared = AuthenticationManager()
    
    private let hashService = PasswordHashingService.shared
    private let store = SecurePasswordStore.shared
    
    // Track failed attempts for brute-force protection
    private var failedAttempts: [String: (count: Int, lastAttempt: Date)] = [:]
    private let maxFailedAttempts = 5
    private let lockoutDuration: TimeInterval = 300 // 5 minutes
    
    private init() {}
    
    enum AuthResult {
        case success
        case invalidCredentials
        case accountLocked(remainingSeconds: Int)
        case userNotFound
        case error(String)
    }
    
    // Register a new user
    func registerUser(username: String, password: String) -> AuthResult {
        let trimmedUsername = username.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        
        guard !trimmedUsername.isEmpty else {
            return .error("Username cannot be empty")
        }
        
        guard password.count >= 8 else {
            return .error("Password must be at least 8 characters")
        }
        
        guard !store.usernameExists(trimmedUsername) else {
            return .error("Username already exists")
        }
        
        guard let hashString = hashService.createHashString(password: password) else {
            return .error("Failed to hash password")
        }
        
        if store.savePasswordHash(forUsername: trimmedUsername, hashString: hashString) {
            return .success
        } else {
            return .error("Failed to save credentials")
        }
    }
    
    // Authenticate user (works offline)
    func authenticateUser(username: String, password: String) -> AuthResult {
        let trimmedUsername = username.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        
        // Check lockout
        if let attempts = failedAttempts[trimmedUsername] {
            if attempts.count >= maxFailedAttempts {
                let elapsed = Date().timeIntervalSince(attempts.lastAttempt)
                if elapsed < lockoutDuration {
                    let remaining = Int(lockoutDuration - elapsed)
                    return .accountLocked(remainingSeconds: remaining)
                } else {
                    // Reset after lockout period
                    failedAttempts.removeValue(forKey: trimmedUsername)
                }
            }
        }
        
        guard let storedHash = store.getPasswordHash(forUsername: trimmedUsername) else {
            return .userNotFound
        }
        
        if hashService.verifyPassword(password, againstHashString: storedHash) {
            // Reset failed attempts on success
            failedAttempts.removeValue(forKey: trimmedUsername)
            return .success
        } else {
            // Track failed attempt
            let current = failedAttempts[trimmedUsername] ?? (count: 0, lastAttempt: Date())
            failedAttempts[trimmedUsername] = (count: current.count + 1, lastAttempt: Date())
            return .invalidCredentials
        }
    }
    
    // Change password
    func changePassword(username: String, currentPassword: String, newPassword: String) -> AuthResult {
        let trimmedUsername = username.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        
        // Verify current password first
        let authResult = authenticateUser(username: trimmedUsername, password: currentPassword)
        
        switch authResult {
        case .success:
            guard newPassword.count >= 8 else {
                return .error("New password must be at least 8 characters")
            }
            
            guard let hashString = hashService.createHashString(password: newPassword) else {
                return .error("Failed to hash new password")
            }
            
            if store.savePasswordHash(forUsername: trimmedUsername, hashString: hashString) {
                return .success
            } else {
                return .error("Failed to save new password")
            }
        default:
            return authResult
        }
    }
    
    // Delete user account
    func deleteUser(username: String, password: String) -> AuthResult {
        let trimmedUsername = username.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        
        let authResult = authenticateUser(username: trimmedUsername, password: password)
        
        switch authResult {
        case .success:
            if store.deletePasswordHash(forUsername: trimmedUsername) {
                return .success
            } else {
                return .error("Failed to delete account")
            }
        default:
            return authResult
        }
    }
    
    // Get remaining attempts before lockout
    func remainingAttempts(forUsername username: String) -> Int {
        let trimmedUsername = username.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let current = failedAttempts[trimmedUsername]?.count ?? 0
        return max(0, maxFailedAttempts - current)
    }
}

