class PasswordViewController: UIViewController {
    
    private let authManager = AuthenticationManager.shared
    
    private let segmentedControl = UISegmentedControl(items: ["Login", "Register"])
    private let usernameTextField = UITextField()
    private let passwordTextField = UITextField()
    private let confirmPasswordTextField = UITextField()
    private let actionButton = UIButton(type: .system)
    private let statusLabel = UILabel()
    private let activityIndicator = UIActivityIndicatorView(style: .gray)
    
    private var isLoginMode = true {
        didSet { updateUI() }
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        updateUI()
    }
    
    private func setupUI() {
        view.backgroundColor = .white
        title = "Secure Password Store"
        
        // Segmented Control
        segmentedControl.selectedSegmentIndex = 0
        segmentedControl.addTarget(self, action: #selector(segmentChanged), for: .valueChanged)
        segmentedControl.translatesAutoresizingMaskIntoConstraints = false
        
        // Username field
        usernameTextField.placeholder = "Username"
        usernameTextField.borderStyle = .roundedRect
        usernameTextField.autocapitalizationType = .none
        usernameTextField.autocorrectionType = .no
        usernameTextField.returnKeyType = .next
        usernameTextField.translatesAutoresizingMaskIntoConstraints = false
        
        // Password field
        passwordTextField.placeholder = "Password"
        passwordTextField.borderStyle = .roundedRect
        passwordTextField.isSecureTextEntry = true
        passwordTextField.returnKeyType = .next
        passwordTextField.translatesAutoresizingMaskIntoConstraints = false
        
        // Confirm password field
        confirmPasswordTextField.placeholder = "Confirm Password"
        confirmPasswordTextField.borderStyle = .roundedRect
        confirmPasswordTextField.isSecureTextEntry = true
        confirmPasswordTextField.returnKeyType = .done
        confirmPasswordTextField.translatesAutoresizingMaskIntoConstraints = false
        
        // Action button
        actionButton.setTitle("Login", for: .normal)
        actionButton.titleLabel?.font = UIFont.boldSystemFont(ofSize: 18)
        actionButton.backgroundColor = UIColor(red: 0.0, green: 0.478, blue: 1.0, alpha: 1.0)
        actionButton.setTitleColor(.white, for: .normal)
        actionButton.layer.cornerRadius = 8
        actionButton.addTarget(self, action: #selector(actionButtonTapped), for: .touchUpInside)
        actionButton.translatesAutoresizingMaskIntoConstraints = false
        
        // Status label
        statusLabel.textAlignment = .center
        statusLabel.numberOfLines = 0
        statusLabel.font = UIFont.systemFont(ofSize: 14)
        statusLabel.translatesAutoresizingMaskIntoConstraints = false
        
        // Activity indicator
        activityIndicator.hidesWhenStopped = true
        activityIndicator.translatesAutoresizingMaskIntoConstraints = false
        
        // Stack view
        let stackView = UIStackView(arrangedSubviews: [
            segmentedControl,
            usernameTextField,
            passwordTextField,
            confirmPasswordTextField,
            actionButton,
            activityIndicator,
            statusLabel
        ])
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -50),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            usernameTextField.heightAnchor.constraint(equalToConstant: 44),
            passwordTextField.heightAnchor.constraint(equalToConstant: 44),
            confirmPasswordTextField.heightAnchor.constraint(equalToConstant: 44),
            actionButton.heightAnchor.constraint(equalToConstant: 50)
        ])
        
        // Tap to dismiss keyboard
        let tap = UITapGestureRecognizer(target: self, action: #selector(dismissKeyboard))
        view.addGestureRecognizer(tap)
    }
    
    private func updateUI() {
        confirmPasswordTextField.isHidden = isLoginMode
        actionButton.setTitle(isLoginMode ? "Login" : "Register", for: .normal)
        statusLabel.text = ""
    }
    
    @objc private func segmentChanged() {
        isLoginMode = segmentedControl.selectedSegmentIndex == 0
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
    
    @objc private func actionButtonTapped() {
        dismissKeyboard()
        
        guard let username = usernameTextField.text, !username.isEmpty else {
            showStatus("Please enter a username", isError: true)
            return
        }
        
        guard let password = passwordTextField.text, !password.isEmpty else {
            showStatus("Please enter a password", isError: true)
            return
        }
        
        activityIndicator.startAnimating()
        actionButton.isEnabled = false
        
        // Run on background thread since hashing can take a moment
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            guard let self = self else { return }
            
            let result: AuthenticationManager.AuthResult
            
            if self.isLoginMode {
                result = self.authManager.authenticateUser(username: username, password: password)
            } else {
                // Verify passwords match for registration
                let confirmPassword = self.confirmPasswordTextField.text ?? ""
                guard password == confirmPassword else {
                    DispatchQueue.main.async {
                        self.activityIndicator.stopAnimating()
                        self.actionButton.isEnabled = true
                        self.showStatus("Passwords do not match", isError: true)
                    }
                    return
                }
                result = self.authManager.registerUser(username: username, password: password)
            }
            
            DispatchQueue.main.async {
                self.activityIndicator.stopAnimating()
                self.actionButton.isEnabled = true
                self.handleResult(result)
            }
        }
    }
    
    private func handleResult(_ result: AuthenticationManager.AuthResult) {
        switch result {
        case .success:
            if isLoginMode {
                showStatus("✅ Authentication successful!", isError: false)
                showAuthenticatedScreen()
            } else {
                showStatus("✅ Registration successful! You can now login.", isError: false)
                segmentedControl.selectedSegmentIndex = 0
                isLoginMode = true
                confirmPasswordTextField.text = ""
            }
            
        case .invalidCredentials:
            let remaining = authManager.remainingAttempts(forUsername: usernameTextField.text ?? "")
            showStatus("❌ Invalid credentials. \(remaining) attempts remaining.", isError: true)
            
        case .accountLocked(let seconds):
            showStatus("🔒 Account locked. Try again in \(seconds) seconds.", isError: true)
            
        case .userNotFound:
            showStatus("❌ User not found. Please register first.", isError: true)
            
        case .error(let message):
            showStatus("⚠️ \(message)", isError: true)
        }
    }
    
    private func showStatus(_ message: String, isError: Bool) {
        statusLabel.text = message
        statusLabel.textColor = isError ? .red : UIColor(red: 0, green: 0.6, blue: 0, alpha: 1)
    }
    
    private func showAuthenticatedScreen() {
        let username = usernameTextField.text ?? ""
        let authenticatedVC = AuthenticatedViewController(username: username)
        authenticatedVC.onLogout = { [weak self] in
            self?.usernameTextField.text = ""
            self?.passwordTextField.text = ""
            self?.statusLabel.text = ""
            self?.dismiss(animated: true)
        }
        let navController = UINavigationController(rootViewController: authenticatedVC)
        navController.modalPresentationStyle = .fullScreen
        present(navController, animated: true)
    }
}

