            field.placeholder = "Password"
            field.isSecureTextEntry = true
        }
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Delete", style: .destructive) { [weak self] _ in
            guard let self = self,
                  let password = alert.textFields?.first?.text else { return }
            
            DispatchQueue.global(qos: .userInitiated).async {
                let result = self.authManager.deleteUser(username: self.username, password: password)
                
                DispatchQueue.main.async {
                    switch result {
                    case .success:
                        self.onLogout?()
                    case .invalidCredentials:
                        self.showAlert(title: "Error", message: "Incorrect password")
                    default:
                        self.showAlert(title: "Error", message: "Failed to delete account")
                    }
                }
            }
        })
        
        present(alert, animated: true)
    }
    
    @objc private func logoutTapped() {
        onLogout?()
    }
    
